#!/bin/bash
# Platform run.sh for H005_focal_loss_calibration — backbone=hyformer + focal loss.
# CLAUDE.md §17.2 one-mutation: PCVRHyFormer-anchor (H001 E_baseline_organizer)
# 와 byte-identical envelope, BCE → focal(α=0.25, γ=2.0) 만 변경. §17.4 rotation
# 첫 충족 (loss_calibration ≠ 직전 H 들의 unified_backbones).
# See README.md §1 + transfer.md §④ for paper-vs-clone deltas.
# Generated by skills/_helpers/build_cloud_package.py — do not hand-edit on platform.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
export PYTHONPATH="${SCRIPT_DIR}:${PYTHONPATH:-}"

# ---------------------------------------------------------------------------
# Platform must set TRAIN_DATA_PATH and TRAIN_CKPT_PATH. Other paths derive.
# ---------------------------------------------------------------------------
: "${TRAIN_DATA_PATH:?TRAIN_DATA_PATH not set by platform}"
: "${TRAIN_CKPT_PATH:?TRAIN_CKPT_PATH not set by platform}"
: "${TRAIN_LOG_PATH:=${TRAIN_CKPT_PATH}/logs}"
: "${TRAIN_TF_EVENTS_PATH:=${TRAIN_CKPT_PATH}/tf_events}"
: "${TRAIN_WORK_PATH:=${TRAIN_CKPT_PATH}/work}"
mkdir -p "${TRAIN_CKPT_PATH}" "${TRAIN_LOG_PATH}" "${TRAIN_TF_EVENTS_PATH}" "${TRAIN_WORK_PATH}"
export TRAIN_LOG_PATH TRAIN_TF_EVENTS_PATH

echo "[run.sh] DATA=${TRAIN_DATA_PATH}"
echo "[run.sh] CKPT=${TRAIN_CKPT_PATH}"
echo "[run.sh] backbone=hyformer + focal(α=0.25, γ=2.0)"

# ---------------------------------------------------------------------------
# Train (PCVRHyFormer + focal loss). Envelope identical to E_baseline_organizer
# (organizer row-group split, train_ratio=0.05, halved seq_max_lens, num_epochs=1).
# Loss is the only mutation (§17.2 one-mutation). NS-token granularity (user=5,
# item=2) intentionally identical to anchor.
# ---------------------------------------------------------------------------
python3 -u "${SCRIPT_DIR}/train.py" \
    --num_epochs 1 \
    --patience 5 \
    --seed 42 \
    --ns_tokenizer_type rankmixer \
    --user_ns_tokens 5 \
    --item_ns_tokens 2 \
    --num_queries 2 \
    --ns_groups_json "" \
    --emb_skip_threshold 1000000 \
    --num_workers 2 \
    --buffer_batches 4 \
    --train_ratio 0.05 \
    --seq_max_lens "seq_a:64,seq_b:64,seq_c:128,seq_d:128" \
    --backbone hyformer \
    --loss_type focal \
    --focal_alpha 0.25 \
    --focal_gamma 2.0 \
    "$@"

echo "[run.sh] training complete (focal calibration); metrics at ${TRAIN_CKPT_PATH}/metrics.json"
